Implement a 4-bit adder with full adders. The output sum should include
the overflow bit.

module TopModule (
  input [3:0] x,
  input [3:0] y,
  output [4:0] sum
);module TopModule (
  input [3:0] x,
  input [3:0] y,
  output [4:0] sum
);

  wire [3:0] carry;

  assign sum[0] = x[0] ^ y[0];
  assign carry[0] = x[0] & y[0];

  genvar i;
  generate
    for (i = 1; i < 4; i = i + 1) begin : gen_full_adder
      assign sum[i] = x[i] ^ y[i] ^ carry[i-1];
      assign carry[i] = (x[i] & y[i]) | (x[i] & carry[i-1]) | (y[i] & carry[i-1]);
    end
  endgenerate

  assign sum[4] = carry[3];

endmodule

