A "population count" circuit counts the number of '1's in an input
vector. Build a population count circuit for a 255-bit input vector.

module TopModule (
  input [254:0] in,
  output reg [7:0] out
);module TopModule (
  input [254:0] in,
  output reg [7:0] out
);

  // Population count circuit for 255-bit input vector

  // Step 1: Compute the number of 1s in each 8-bit group
  reg [7:0] count0, count1, count2, count3, count4, count5, count6, count7;

  always @(*) begin
    count0 = in[7:0];
    count1 = in[15:8];
    count2 = in[23:16];
    count3 = in[31:24];
    count4 = in[39:32];
    count5 = in[47:40];
    count6 = in[55:48];
    count7 = in[63:56];
  end

  // Step 2: Compute the number of 1s in each 64-bit group
  reg [7:0] count8, count9, count10, count11, count12, count13, count14, count15;

  always @(*) begin
    count8 = count0 + count1;
    count9 = count2 + count3;
    count10 = count4 + count5;
    count11 = count6 + count7;
    count12 = count8 + count9;
    count13 = count10 + count11;
    count14 = count12 + count13;
    count15 = count14 + count15;
  end

  // Step 3: Compute the final population count
  always @(*) begin
    out = count15;
  end

endmodule

