output. Implement this state machine in Verilog. Reset is an active-high
synchronous reset to state OFF.

  OFF (out=0) --j=0--> OFF
  OFF (out=0) --j=1--> ON
  ON  (out=1) --k=0--> ON
  ON  (out=1) --k=1--> OFF

module TopModule (
  input clk,
  input j,
  input k,
  input reset,
  output out
);module TopModule (
  input clk,
  input j,
  input k,
  input reset,
  output out
);

  // Define the states
  typedef enum reg [1:0] {
    OFF = 2'b00,
    ON  = 2'b01
  } state_t;

  // State and next state registers
  state_t state, next_state;

  // Output logic (Moore machine)
  assign out = (state == ON) ? 1'b1 : 1'b0;

  // State transition logic
  always @(*) begin
    case (state)
      OFF: begin
        if (j == 1'b1) next_state = ON;
        else next_state = OFF;
      end
      ON: begin
        if (k == 1'b1) next_state = OFF;
        else next_state = ON;
      end
      default: next_state = OFF;
    endcase
  end

  // Synchronous state update
  always @(posedge clk) begin
    if (reset) begin
      state <= OFF;
    end else begin
      state <= next_state;
    end
  end

endmodule

