    if (load) begin
      q <= data;
    end else begin
      reg [2:0] left, center, right;
      reg [2:0] next_state;
      reg [511:0] next_q;

      for (int i = 0; i < 512; i = i + 1) begin
        left = {q[i+1], q[i], q[i-1]};
        center = q[i];
        right = {q[i-1], q[i], q[i+1]};

        case ({left, center, right})
          3'b111: next_state = 3'b000;
          3'b110: next_state = 3'b001;
          3'b101: next_state = 3'b011;
          3'b100: next_state = 3'b000;
          3'b011: next_state = 3'b011;
          3'b010: next_state = 3'b011;
          3'b001: next_state = 3'b011;
          3'b000: next_state = 3'b000;
        endcase

        next_q[i] = next_state[0];
      end
      q <= next_q;
    end
  end

