  input areset,
  input bump_left,
  input bump_right,
  output walk_left,
  output walk_right
);module TopModule (
  input clk,
  input areset,
  input bump_left,
  input bump_right,
  output reg walk_left,
  output reg walk_right
);

  // Define the state type and initial state
  typedef enum reg [1:0] {
    WALK_LEFT = 2'b01,
    WALK_RIGHT = 2'b10
  } state_t;

  state_t current_state, next_state;

  // State transition logic
  always @(*) begin
    next_state = current_state;
    if (areset) begin
      next_state = WALK_LEFT;
    end else begin
      if (bump_left) begin
        next_state = WALK_RIGHT;
      end else if (bump_right) begin
        next_state = WALK_LEFT;
      end
    end
  end

  // Output logic (Moore machine)
  always @(*) begin
    case (next_state)
      WALK_LEFT: begin
        walk_left = 1'b1;
        walk_right = 1'b0;
      end
      WALK_RIGHT: begin
        walk_left = 1'b0;
        walk_right = 1'b1;
      end
    endcase
  end

  // State register
  always @(posedge clk) begin
    current_state <= next_state;
  end

endmodule

The PS/2 mouse protocol sends messages that are three bytes long.
However, within a continuous byte stream, it's not obvious where messages
start and end. The only indication is that the first byte of each three
byte message always has in[3]=1 (but in[3] of the other two bytes may be
1 or 0 depending on data). We want a finite state machine that will
search for message boundaries when given an input byte stream. The
algorithm we'll use is to discard bytes until we see one with in[3]=1. We
then assume that this is byte 1 of a message, and signal the receipt of a
message once all 3 bytes have been received (done). The FSM should signal
done in the cycle immediately after the third byte of each message was
successfully received. Reset should be active high synchronous.

module TopModule (
  input clk,
  input [7:0] in,
  input reset,
  output done
);module TopModule (
  input clk,
  input [7:0] in,
  input reset,
  output done
);

  // State definition
  typedef enum reg [1:0] {
    S_IDLE,
    S_WAITING_FOR_START,
    S_RECEIVING_BYTES
  } state_t;

  state_t state, next_state;

  // Output signal
  reg done;

  // State transition logic
  always @(posedge clk) begin
    if (reset) begin
      state <= S_IDLE;
      done <= 1'b0;
    end else begin
      state <= next_state;
      done <= 1'b0;
    end
  end

  // Next state logic
  always @* begin
    next_state = state;
    done = 1'b0;

    case (state)
      S_IDLE: begin
        if (in[3]) begin
          next_state = S_RECEIVING_BYTES;
          done = 1'b0;
        end else begin
          next_state = S_IDLE;
          done = 1'b0;
        end
      end

      S_RECEIVING_BYTES: begin
        if (in[3]) begin
          next_state = S_RECEIVING_BYTES;
          done = 1'b0;
        end else begin
          next_state = S_WAITING_FOR_START;
          done = 1'b0;
        end
      end

      S_WAITING_FOR_START: begin
        if (in[3]) begin
          next_state = S_RECEIVING_BYTES;
          done = 1'b0;
        end else begin
          next_state = S_WAITING_FOR_START;
          done = 1'b0;
        end
      end
    endcase
  end

endmodule

