  input clk,
  input in,
  input reset,
  output done
);module TopModule (
  input clk,
  input in,
  input reset,
  output done
);

  // Define the states of the FSM
  typedef enum reg [2:0] {
    IDLE,        // Waiting for start bit
    START,       // Start bit received
    DATA,        // Receiving data bits
    STOP,        // Stop bit received
    ERROR        // Stop bit not received
  } state_t;

  // State and next state registers
  state_t state, next_state;

  // Output register for done signal
  reg done;

  // State transition logic
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state <= IDLE;
      done <= 0;
    end else begin
      state <= next_state;
      done <= 0;
    end
  end

  // Next state logic
  always @(*) begin
    next_state = state;
    done = 0;

    case (state)
      IDLE: begin
        if (in == 1'b0) begin
          next_state = START;
        end
      end

      START: begin
        next_state = DATA;
      end

      DATA: begin
        if (in == 1'b1) begin
          next_state = STOP;
        end
      end

      STOP: begin
        if (in == 1'b1) begin
          next_state = IDLE;
          done = 1;
        end else begin
          next_state = ERROR;
        end
      end

      ERROR: begin
        next_state = IDLE;
      end
    endcase
  end

endmodule

