  input clk,
  input load,
  input [255:0] data,
  output reg [255:0] q
);module TopModule (
  input clk,
  input load,
  input [255:0] data,
  output reg [255:0] q
);

  always @(posedge clk) begin
    if (load) begin
      q <= data;
    end else begin
      reg [255:0] next_q;
      reg [3:0] count;
      reg [3:0] i, j, k, l;
      reg [3:0] row, col;
      reg [3:0] neighbors;
      reg [3:0] current;
      reg [3:0] next;

      for (i = 0; i < 16; i = i + 1) begin
        for (j = 0; j < 16; j = j + 1) begin
          row = i;
          col = j;
          neighbors = 0;
          for (k = 0; k < 3; k = k + 1) begin
            for (l = 0; l < 3; l = l + 1) begin
              if (k == 1 && l == 1) continue;
              current = q[(row + k) % 16 * 16 + (col + l) % 16];
              neighbors = neighbors + current;
            end
          end
          next = (neighbors == 3) ? 1 : (neighbors == 2) ? q[(row * 16) + col] : 0;
          next_q[(row * 16) + col] = next;
        end
      end
      q <= next_q;
    end
  end

endmodule

